module full_adder_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);

wire [3:0] carry;

assign {carry[0], sum[0]} = a[0] + b[0] + cin;
assign {carry[1], sum[1]} = a[1] + b[1] + carry[0];
assign {carry[2], sum[2]} = a[2] + b[2] + carry[1];
assign {carry[3], sum[3]} = a[3] + b[3] + carry[2];
assign cout = carry[3];

  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~b[1];
      cout <= carry[2];
    end
  end

endmodule
